sql.where:
p.USE_YN = 'Y'
AND p.APPROVE_STATE != 'WORK'

AND p.PAGE_TYPE = 'PAGE'

    AND p.APPROVE_STATE = #{req.approveState}


    AND p.CREATE_USER_ID = #{req.createUserId}


    AND (
        p.PAGE_NAME LIKE '%' || #{req.search} || '%'
        OR p.CREATE_USER_NAME LIKE '%' || #{req.search} || '%'
    )

mapper.select:
SELECT * FROM (
    SELECT INNER_QRY.*, ROWNUM AS RNUM FROM (
        SELECT

        FROM SPW_CMS_PAGE p


    ) INNER_QRY
    WHERE ROWNUM <= #{endRow}
) WHERE RNUM > #{offset}

mapper.update:
UPDATE SPW_CMS_PAGE
SET IS_PUBLIC        = #{isPublic},
    LAST_MODIFIER_ID = #{modifierId}
WHERE PAGE_ID   = #{pageId}
  AND PAGE_TYPE = 'PAGE'

UPDATE SPW_CMS_PAGE
SET BEGINNING_DATE   = TO_DATE(#{beginningDate}, 'YYYY-MM-DD'),
    EXPIRED_DATE     = TO_DATE(#{expiredDate}, 'YYYY-MM-DD'),
    LAST_MODIFIER_ID = #{modifierId}
WHERE PAGE_ID   = #{pageId}
  AND PAGE_TYPE = 'PAGE'

mapper.select:
SELECT NVL(MAX(VERSION), 0) + 1
FROM SPW_CMS_PAGE_HISTORY
WHERE PAGE_ID = #{pageId}

SELECT
    h.PAGE_HTML  AS pageHtml,
    h.FILE_PATH  AS filePath
FROM SPW_CMS_PAGE_HISTORY h
WHERE h.PAGE_ID = #{pageId}
  AND h.VERSION  = #{version}
